def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 04: Merge Analysis Dataset")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Confidence theta scores from Step 01 and cognitive tests from Step 02
        # Purpose: Merge these datasets to create analysis-ready dataset for regression

        log("[LOAD] Loading confidence theta scores...")
        # Load confidence theta scores (100 participants expected)
        # Expected columns: ['UID', 'confidence_theta', 'se_theta']
        # Expected rows: ~100
        confidence_df = pd.read_csv(RQ_DIR / "data/step01_confidence_theta.csv")
        log(f"[LOADED] step01_confidence_theta.csv ({len(confidence_df)} rows, {len(confidence_df.columns)} cols)")
        
        log("[LOAD] Loading cognitive test scores...")
        # Load cognitive test T-scores and demographics (100 participants expected)
        # Expected columns: ['UID', 'RAVLT_T', 'BVMT_T', 'RPM_T', 'age', 'sex', 'education']
        # Expected rows: ~100
        # Note: Step 03 was skipped because Step 02 already created T-scores
        cognitive_df = pd.read_csv(RQ_DIR / "data/step02_cognitive_tests.csv")
        log(f"[LOADED] step02_cognitive_tests.csv ({len(cognitive_df)} rows, {len(cognitive_df.columns)} cols)")

        # =========================================================================
        # STEP 2: Run Analysis Tool (pandas merge)
        # =========================================================================
        # Tool: pd.merge (stdlib pandas function)
        # What it does: Inner join on UID to combine confidence and cognitive data
        # Expected output: Merged dataset with participants who have both types of data

        log("[ANALYSIS] Running pd.merge for inner join on UID...")
        
        # Merge datasets using inner join on UID
        # This ensures only participants with both confidence and cognitive data are included
        merged_df = pd.merge(
            left=confidence_df,
            right=cognitive_df,
            on="UID",  # merge_key parameter
            how="inner"  # merge_type parameter  
        )
        log(f"[MERGE] Inner join complete: {len(merged_df)} participants with complete data")
        
        # Drop se_theta column as it's not needed for regression analysis
        # Final dataset should have: UID, confidence_theta, RAVLT_T, BVMT_T, RPM_T, age, sex, education
        if 'se_theta' in merged_df.columns:
            merged_df = merged_df.drop(columns=['se_theta'])
            log("[DROP] Removed se_theta column (not needed for regression)")
        
        # Check for missing values and report
        missing_counts = merged_df.isnull().sum()
        total_missing = missing_counts.sum()
        
        if total_missing > 0:
            log(f"[WARNING] Found {total_missing} missing values:")
            for col, count in missing_counts.items():
                if count > 0:
                    log(f"  {col}: {count} missing")
            
            # Drop rows with any missing values (drop_missing parameter)
            initial_rows = len(merged_df)
            merged_df = merged_df.dropna()
            final_rows = len(merged_df)
            
            if final_rows < initial_rows:
                log(f"[CLEAN] Dropped {initial_rows - final_rows} rows with missing values")
                log(f"[CLEAN] Final complete-case dataset: {final_rows} participants")
        else:
            log("[CLEAN] No missing values found - dataset is complete")

        log("[DONE] Analysis complete")

        # =========================================================================
        # STEP 3: Save Analysis Outputs
        # =========================================================================
        # These outputs will be used by: Step 05 (hierarchical regression) and subsequent analyses

        log(f"[SAVE] Saving step04_analysis_dataset.csv...")
        # Output: step04_analysis_dataset.csv
        # Contains: Merged analysis-ready dataset with complete cases
        # Columns: ['UID', 'confidence_theta', 'RAVLT_T', 'BVMT_T', 'RPM_T', 'age', 'sex', 'education']
        output_path = RQ_DIR / "data/step04_analysis_dataset.csv"
        merged_df.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] step04_analysis_dataset.csv ({len(merged_df)} rows, {len(merged_df.columns)} cols)")
        
        # Log final dataset summary
        log(f"[SUMMARY] Final dataset columns: {list(merged_df.columns)}")
        log(f"[SUMMARY] Sample size: {len(merged_df)} participants")

        # =========================================================================
        # STEP 4: Run Validation Tool
        # =========================================================================
        # Tool: tools.validation.validate_dataframe_structure
        # Validates: DataFrame has expected structure and sample size
        # Threshold: Final sample size >= 90 participants

        log("[VALIDATION] Running validate_dataframe_structure...")
        
        # Expected columns for final dataset
        expected_cols = ['UID', 'confidence_theta', 'RAVLT_T', 'BVMT_T', 'RPM_T', 'RAVLT_Pct_Ret_T', 'BVMT_Pct_Ret_T', 'age', 'sex', 'education']
        
        validation_result = validate_dataframe_structure(
            df=merged_df,
            expected_rows=(90, 105),  # Range: minimum 90, maximum ~105
            expected_columns=expected_cols,  # Required columns
            column_types=None  # No specific type checking needed
        )

        # Report validation results
        # Expected: All validation checks should pass for proper merge
        if isinstance(validation_result, dict):
            if validation_result.get('valid', False):
                log("[VALIDATION] Dataset structure validation PASSED")
                for check_name, check_result in validation_result.get('checks', {}).items():
                    status = "PASS" if check_result else "FAIL"
                    log(f"[VALIDATION] {check_name}: {status}")
            else:
                log(f"[VALIDATION] Dataset structure validation FAILED: {validation_result.get('message', 'Unknown error')}")
        else:
            log(f"[VALIDATION] {validation_result}")

        log("[SUCCESS] Step 04 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)